BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?type ?name ?client ?supplier WHERE {
  ?elem vocab:NamedElement_name ?name .
  FILTER(
    CONTAINS(LCASE(STR(?name)), LCASE("executive")) ||
    CONTAINS(LCASE(STR(?name)), LCASE("analysis%20software")) ||
    CONTAINS(LCASE(STR(?name)), LCASE("analys")) ||
    CONTAINS(LCASE(STR(?name)), LCASE("proced"))
  )
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:Dependency_client ?client . }
  OPTIONAL { ?elem vocab:Dependency_supplier ?supplier . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?rel ?relName ?asClient ?asSupplier WHERE {
  ?rel rdf:type vocab:dependency .
  ?rel vocab:NamedElement_name ?relName .
  VALUES ?me {
    <http://api.koneksys.com/cameo/TMT/executive%20software/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::APS::Realization%2520Design::Software%2520Architecture%2520(deprecated)::Executive%2520Software::Procedure%2520Executive%2520and%2520Analysis%2520Software%2520-PEAS>
    <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::APS::Conceptual%2520Design::Components::Procedure%2520Executive%2520and%2520Analysis%2520Software>
  }
  OPTIONAL { ?rel vocab:Dependency_client ?me . BIND(?relName as ?asClient) }
  OPTIONAL { ?rel vocab:Dependency_supplier ?me . BIND(?relName as ?asSupplier) }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?port ?portName ?ptype ?provided ?required WHERE {
  ?port rdf:type vocab:port .
  ?port vocab:NamedElement_name ?portName .
  FILTER(
    CONTAINS(LCASE(STR(?portName)), LCASE("peas")) ||
    CONTAINS(LCASE(STR(?portName)), LCASE("procedure%20execut")) ||
    CONTAINS(LCASE(STR(?portName)), LCASE("analysis"))
  )
  OPTIONAL { ?port vocab:Port_provided ?provided . }
  OPTIONAL { ?port vocab:Port_required ?required . }
  OPTIONAL { ?port rdf:type ?ptype . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?port ?portName ?provided ?required ?providerOf ?requiredOf WHERE {
  ?port rdf:type vocab:port .
  ?port vocab:NamedElement_name ?portName .
  FILTER(
    CONTAINS(LCASE(STR(?portName)), LCASE("PEAS2")) ||
    CONTAINS(LCASE(STR(?portName)), LCASE("PEAS"))
  )

  OPTIONAL { ?port vocab:Port_provided ?provided . }
  OPTIONAL { ?port vocab:Port_required ?required . }

  OPTIONAL {
    ?conn rdf:type vocab:connector ;
          vocab:Connector_end ?endA ;
          vocab:Connector_end ?endB .
    ?endA vocab:ConnectorEnd_role ?port .
    ?endB vocab:ConnectorEnd_role ?otherPort .
    ?otherPort vocab:NamedElement_name ?requiredOf .
  }
  OPTIONAL {
    ?conn2 rdf:type vocab:connector ;
           vocab:Connector_end ?endA2 ;
           vocab:Connector_end ?endB2 .
    ?endA2 vocab:ConnectorEnd_role ?port .
    ?endB2 vocab:ConnectorEnd_role ?otherPort2 .
    ?otherPort2 vocab:NamedElement_name ?providerOf .
  }
}
LIMIT 25
